import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import InicioSesion from "./inicioSesion";

const Header = () => {
  const navigate = useNavigate();
  const [loggedIn, setLoggedIn] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [userInfo, setUserInfo] = useState(null);

  useEffect(() => {
    const storedLoggedIn = localStorage.getItem("loggedIn") === "true";
    const storedUserInfo = localStorage.getItem("userInfo");
    setLoggedIn(storedLoggedIn);
    if (storedUserInfo) {
      setUserInfo(JSON.parse(storedUserInfo));
    }
    
    const checkLoginStatus = () => {
      const logged = localStorage.getItem("loggedIn") === "true";
      setLoggedIn(logged);
      const user = localStorage.getItem("userInfo");
      setUserInfo(user ? JSON.parse(user) : null);
    };

    window.addEventListener("storage", checkLoginStatus);
    return () => window.removeEventListener("storage", checkLoginStatus);
  }, []);

  const handleLoginClick = () => setShowLogin(true);

  // Aquí ya NO haces petición. Solo guardas el usuario recibido desde InicioSesion
  const handleLoginSuccess = (usuario) => {
    localStorage.setItem("loggedIn", "true");
    localStorage.setItem("userInfo", JSON.stringify(usuario));
    setUserInfo(usuario);
    setLoggedIn(true);
    setShowLogin(false);
  };

  const handleCloseLogin = () => setShowLogin(false);

  const handleUserClick = () => setMenuOpen((prev) => !prev);

  const handleLogout = () => {
    localStorage.removeItem("loggedIn");
    localStorage.removeItem("userInfo");
    setUserInfo(null);
    setLoggedIn(false);
    setMenuOpen(false);
    navigate("/");
  };

  const styles = {
    /* Tus estilos aquí, sin cambios */
  };

  return (
    <>
      <header style={styles.header}>
        {/* Tu código de header, igual */}
        <img
          src="/media/header/login.png"
          alt={loggedIn ? "Cerrar sesión" : "Iniciar sesión"}
          style={styles.iconImg}
          onClick={loggedIn ? handleUserClick : handleLoginClick}
          draggable={false}
          title={loggedIn ? "Cerrar sesión" : "Iniciar sesión"}
        />
        {loggedIn && menuOpen && (
          <div style={styles.dropdown}>
            <div
              style={styles.dropdownItem}
              onClick={() => {
                navigate("/editor-empresas");
                setMenuOpen(false);
              }}
            >
              Admin.Empresas
            </div>
            <div
              style={styles.dropdownItem}
              onClick={() => {
                navigate("/editor-usuarios");
                setMenuOpen(false);
              }}
            >
              Admin.Usuarios
            </div>
            <div
              style={{ ...styles.dropdownItem, color: "red", borderBottom: "none" }}
              onClick={handleLogout}
            >
              Cerrar Sesión
            </div>
          </div>
        )}
      </header>

      {showLogin && <InicioSesion onLogin={handleLoginSuccess} onClose={handleCloseLogin} />}
    </>
  );
};

export default Header;
